(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[4607],{607:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>e});const e={key:"v-ddf72cb6",path:"/pages/javascript/es6/",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:3,title:"Symbol使用技巧",slug:"symbol使用技巧",children:[]},{level:3,title:"flatMap",slug:"flatmap",children:[]},{level:3,title:"WeakMap 弱引用的只是键名，而不是键值。键值依然是正常引用",slug:"weakmap-弱引用的只是键名-而不是键值。键值依然是正常引用",children:[]},{level:3,title:"WeakSet与Set的差异",slug:"weakset与set的差异",children:[]},{level:3,title:"WeakMap与Map的差异",slug:"weakmap与map的差异",children:[]},{level:3,title:"输出结果",slug:"输出结果",children:[]},{level:3,title:"class类无法遍历它实例原型链上的属性和方法",slug:"class类无法遍历它实例原型链上的属性和方法",children:[]},{level:3,title:"new.target",slug:"new-target",children:[]},{level:3,title:"for await 异步迭代器",slug:"for-await-异步迭代器",children:[]},{level:3,title:"FileReader",slug:"filereader",children:[]}],filePathRelative:"pages/javascript/es6/README.md",git:{updatedTime:1716447612e3,contributors:[{name:"COOKIES-LGL",email:"1344714332@qq.com",commits:9},{name:"guilin.li",email:"1344714332@qq.com",commits:2}]}}},8094:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>p});const e=(0,a(6252).uE)('<h3 id="symbol使用技巧"><a class="header-anchor" href="#symbol使用技巧">#</a> Symbol使用技巧</h3><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>symbol 作为对象的属性无法通过.运算符获取,需要使用[symbol] 全局共享Symbol let a = Symbol.for(&quot;a&quot;) let b = Symbol.for(&quot;a&quot;) a === b // true Symbol.keyFor(a) 可以通过变量名查询该变量名对应的Symbol是否在全局注册表中</p></div><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>我们还可以通过更改内置Symbol值对应的方法来达到更改外部方法作用的效果。 class demo {    static <a href="item">Symbol.hasInstance</a> {        return item === &quot;恶霸&quot;   } } &quot;恶霸&quot; instanceof demo // true Symbol.hasInstance对应的外部方法是instanceof，这个大家熟悉吧，经常用于判断类型。而在上面的代码片段中，我创建了一个demo类，并重写了Symbol.hasInstance，所以其对应的instanceof行为也会发生改变，其内部的机制是这样的：当我们调用instanceof方法的时候，内部对应调用Symbol.hasInstance对应的方法即return item === &quot;恶霸&quot;</p></div><h3 id="flatmap"><a class="header-anchor" href="#flatmap">#</a> flatMap</h3><p>只能增加数组元素不能减少</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> arr1 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">;</span>\n\n<span class="token keyword">const</span> result <span class="token operator">=</span> arr1<span class="token punctuation">.</span><span class="token function">flatMap</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">num</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">(</span>num <span class="token operator">===</span> <span class="token number">2</span> <span class="token operator">?</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">]</span> <span class="token operator">:</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>result<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token comment">// Expected output: Array [1, 2, 2, 1]</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="weakmap-弱引用的只是键名-而不是键值。键值依然是正常引用"><a class="header-anchor" href="#weakmap-弱引用的只是键名-而不是键值。键值依然是正常引用">#</a> WeakMap 弱引用的只是键名，而不是键值。键值依然是正常引用</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> wm <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">WeakMap</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token keyword">let</span> key <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>\n<span class="token keyword">let</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span>foo<span class="token operator">:</span> <span class="token number">1</span><span class="token punctuation">}</span><span class="token punctuation">;</span>\n\nwm<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span>key<span class="token punctuation">,</span> obj<span class="token punctuation">)</span><span class="token punctuation">;</span>\nobj <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>\nwm<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span>key<span class="token punctuation">)</span>\n<span class="token comment">// Object {foo: 1}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="weakset与set的差异"><a class="header-anchor" href="#weakset与set的差异">#</a> WeakSet与Set的差异</h3><ul><li>对于WeakSet实例，若调用了add()方法时传入了非对象的参数，则会抛出错误。如果在has()或者delete()方法中传入了非对象的参数则会返回false；</li><li>Weak Set不可迭代，因此不能用于for-of循环；</li><li>Weak Set 无法暴露出任何迭代器（例如 keys() 与 values() 方法） ，因此没有任何编程手段可用于判断 Weak Set 的内容；</li><li>Weak Set没有forEach()方法；</li><li>Weak Set没有size属性；</li></ul><h3 id="weakmap与map的差异"><a class="header-anchor" href="#weakmap与map的差异">#</a> WeakMap与Map的差异</h3><ul><li>WeakMap的键必须是对象，值可以是任意类型</li><li>可以使用has()方法来检查Weak Map中是否存在某一个键值对，使用delete()方法可以删除一个键值对。</li><li>clear() 方法不存在，</li><li>Weak Map 只为它们的内容提供了很小的可见度，因此你不能使用 forEach() 方法、size 属性或 clear() 方法来管理其中的项</li><li>这是因为没必要对键进行枚举, 并且枚举 Weak Map 也是不可能的</li></ul><h3 id="输出结果"><a class="header-anchor" href="#输出结果">#</a> 输出结果</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>Promise<span class="token punctuation">.</span><span class="token function">resolve</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> Promise<span class="token punctuation">.</span><span class="token function">resolve</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>核心就是会比正常的return一个非Promise的值时，多两个微任务.then().then()</p><h3 id="class类无法遍历它实例原型链上的属性和方法"><a class="header-anchor" href="#class类无法遍历它实例原型链上的属性和方法">#</a> class类无法遍历它实例原型链上的属性和方法</h3><h3 id="new-target"><a class="header-anchor" href="#new-target">#</a> new.target</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// new.target属性允许你检测函数或构造方法是否是通过new运算符被调用的</span>\n<span class="token keyword">function</span> <span class="token function">Foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span><span class="token keyword">new</span><span class="token punctuation">.</span>target<span class="token punctuation">)</span> <span class="token keyword">throw</span> <span class="token string">&quot;Foo() must be called with new&quot;</span><span class="token punctuation">;</span>\n  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;Foo instantiated with new&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n<span class="token function">Foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// throws &quot;Foo() must be called with new&quot;</span>\n<span class="token keyword">new</span> <span class="token class-name">Foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// logs &quot;Foo instantiated with new&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="for-await-异步迭代器"><a class="header-anchor" href="#for-await-异步迭代器">#</a> for await 异步迭代器</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">async</span> <span class="token keyword">function</span><span class="token operator">*</span> <span class="token function">myAsyncIterator</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">yield</span> <span class="token number">1</span><span class="token punctuation">;</span>\n  <span class="token keyword">await</span> <span class="token keyword">new</span> <span class="token class-name">Promise</span><span class="token punctuation">(</span><span class="token parameter">resolve</span> <span class="token operator">=&gt;</span> <span class="token function">setTimeout</span><span class="token punctuation">(</span>resolve<span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n  <span class="token keyword">yield</span> <span class="token number">2</span><span class="token punctuation">;</span>\n  <span class="token keyword">yield</span> <span class="token number">3</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">for</span> <span class="token keyword">await</span> <span class="token punctuation">(</span><span class="token keyword">let</span> value <span class="token keyword">of</span> <span class="token function">myAsyncIterator</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span><span class="token punctuation">;</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n<span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h3 id="filereader"><a class="header-anchor" href="#filereader">#</a> FileReader</h3><p>如果想要读取Blob或者文件对象并转化为其他格式的数据，可以借助FileReader对象的API进行操作</p><ul><li>FileReader.readAsText(Blob)：将Blob转化为文本字符串</li><li>FileReader.readAsArrayBuffer(Blob)：将Blob转为ArrayBuffer格式数据</li><li>FileReader.readAsDataURL(): 将Blob转化为Base64格式的Data URL</li></ul>',23),p={render:function(n,s){return e}}}}]);